// Compress the Movers & Shakers HTML to product titles + ranks for the next step.
// If fetch failed, return empty trends array — Claude will fall back to internal knowledge.
const raw = $input.first().json.body || $input.first().json.data || '';
if (!raw || raw.length < 1000) {
  return [{ json: { trends: [], status: 'empty_or_blocked' } }];
}
const asinMatches = [...raw.matchAll(/\/dp\/([A-Z0-9]{10})/g)];
const titleMatches = [...raw.matchAll(/aria-label="([^"]{20,200})"/g)];
const trends = [];
const seen = new Set();
for (let i = 0; i < Math.min(30, asinMatches.length); i++) {
  const asin = asinMatches[i][1];
  if (seen.has(asin)) continue;
  seen.add(asin);
  trends.push({ asin, rank: i + 1, title_hint: titleMatches[i] ? titleMatches[i][1] : '' });
}
return [{ json: { trends, status: 'fetched', count: trends.length } }];

// Parse Claude's JSON output and return as array of products
const raw = $input.first().json.content[0].text;
const products = JSON.parse(raw);
return products.map(p => ({ json: p }));

const raw = $input.first().json.content[0].text;
const script = JSON.parse(raw);
const product = $('Split In Batches').item.json;
return [{ json: { product, script } }];
